using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API.
/// Uses constructor-injected HttpClient and ILogger — both resolved via DI
/// and hidden from the tool's JSON schema (only [Description] parameters are exposed).
/// </summary>
[McpServerToolType]
public class JsonPlaceholderTools(HttpClient httpClient, ILogger<JsonPlaceholderTools> logger)
{
    [McpServerTool, Description("Get a post by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The post ID (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var post = await httpClient.GetFromJsonAsync<Post>($"/posts/{id}", cancellationToken);
        return $"Title: {post!.Title}\n\n{post.Body}";
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts by this user ID (optional)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        var posts = await httpClient.GetFromJsonAsync<Post[]>(url, cancellationToken);
        return string.Join("\n", posts!.Select(p => $"[{p.Id}] {p.Title}"));
    }

    [McpServerTool, Description("Search for users by name (case-insensitive substring match).")]
    public async Task<string> SearchUsers(
        [Description("Name or partial name to search for")] string query,
        CancellationToken cancellationToken = default)
    {
        var users = await httpClient.GetFromJsonAsync<User[]>("/users", cancellationToken);
        var matches = users!
            .Where(u => u.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
            .ToList();

        return matches.Count == 0
            ? "No users found."
            : string.Join("\n", matches.Select(u => $"{u.Name} ({u.Email})"));
    }
}

public record Post(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);

public record User(
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("email")] string Email);

